// Derives per-prop controls from each sketchbook component's TypeScript Props type
// and writes them to src/auto-argtypes.generated.ts. Run this when a sketchbook
// component's props change: `yarn gen-controls`.
//
// The extraction is done by the native typescript-go extractor built at ~/src/tsgolint
// (it lives outside this repo and is referenced locally). Set EXTRACT_PROPS_BIN to
// override its path. The generated file is committed, so the studio develops without
// needing the extractor present — you only need it to regenerate.
import { execFileSync } from 'node:child_process'
import { globSync, writeFileSync } from 'node:fs'
import os from 'node:os'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const packageDir = path.join(path.dirname(fileURLToPath(import.meta.url)), '..')
const srcDir = path.join(packageDir, 'src')
const bin = process.env.EXTRACT_PROPS_BIN ?? path.join(os.homedir(), 'src/tsgolint/extract-props')

const files = globSync('sketchbooks/**/*.sketchbook.tsx', { cwd: srcDir }).map((f) =>
	path.join('src', f)
)
if (files.length === 0) {
	console.warn('gen-controls: no sketchbooks found')
	process.exit(0)
}

const stdout = execFileSync(bin, ['tsconfig.json', ...files], {
	cwd: packageDir,
	encoding: 'utf8',
	maxBuffer: 16 * 1024 * 1024,
})

// Re-key absolute paths to src-relative, matching import.meta.glob keys in registry.ts.
const byAbs = JSON.parse(stdout)
const bySrcRel = {}
for (const abs of Object.keys(byAbs).sort()) {
	bySrcRel[path.relative(srcDir, abs)] = byAbs[abs]
}

const contents = `// Generated by \`yarn gen-controls\` from component Props types. Do not edit.
// Regenerate when a sketchbook component's props change.
import { ArgType } from './sketch'

export const autoArgTypes: Record<string, Record<string, ArgType>> = ${JSON.stringify(bySrcRel, null, '\t')}
`

writeFileSync(path.join(srcDir, 'auto-argtypes.generated.ts'), contents)
console.log(`gen-controls: wrote controls for ${Object.keys(bySrcRel).length} sketchbook(s)`)
